#include <iostream>
using namespace std;

int main() {
    int x = 10, y = 3;

    // Арифметика
    cout << "x + y = " << x + y << endl;  // 13
    cout << "x - y = " << x - y << endl;  // 7
    cout << "x * y = " << x * y << endl;  // 30
    cout << "x / y = " << x / y << endl;  // 3 (целочисленное)
    cout << "x % y = " << x % y << endl;  // 1

    // Сравнение
    cout << (x > y) << endl;  // 1 (true)
    cout << (x == y) << endl; // 0 (false)

    // Логические
    cout << ((x > 5) && (y < 5)) << endl; // 1 (true)
    cout << ((x == 5) || (y == 3)) << endl; // 1 (true)

    return 0;
}

