#include <iostream>
using namespace std;

int main() {
    // Цикл for - вывод чисел от 1 до 5
    cout << "For loop:" << endl;
    for (int i = 1; i <= 5; i++) {
        cout << i << " ";
    }
    cout << endl;

    // Цикл while - вывод чисел от 10 до 6
    cout << "While loop:" << endl;
    int j = 10;
    while (j >= 6) {
        cout << j << " ";
        j--;
    }
    cout << endl;

    // Цикл do-while - минимум 1 выполнение
    cout << "Do-while loop:" << endl;
    int k = 1;
    do {
        cout << k << " ";
        k++;
    } while (k <= 3);
    cout << endl;

    // Вычисление суммы чисел от 1 до 100
    int sum = 0;
    for (int i = 1; i <= 100; i++) {
        sum += i;
    }
    cout << "Сумма от 1 до 100: " << sum << endl;  // 5050

    return 0;
}

