#include <iostream>
using namespace std;

int main() {
    int numbers[5] = {10, 20, 30, 40, 50};

    // Доступ к элементам
    cout << "First element: " << numbers[0] << endl;  // 10
    cout << "Third element: " << numbers[2] << endl;  // 30

    // Изменение элемента
    numbers[1] = 25;
    cout << "Changed second element: " << numbers[1] << endl;  // 25

    // Перебор массива
    cout << "All elements: ";
    for (int i = 0; i < 5; i++) {
        cout << numbers[i] << " ";
    }
    cout << endl;

    // Вычисление суммы
    int sum = 0;
    for (int i = 0; i < 5; i++) {
        sum += numbers[i];
    }
    cout << "Sum: " << sum << endl;

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

int main() {
    string name = "Alice";
    string greeting = "Hello, " + name + "!";

    cout << greeting << endl;  // Hello, Alice!
    cout << "Length: " << name.length() << endl;  // 5

    // Доступ к символам
    cout << "First char: " << name[0] << endl;  // A

    // Подстрока
    cout << "Substring: " << name.substr(0, 2) << endl;  // Al

    // Поиск
    int pos = name.find('l');
    cout << "Position of 'l': " << pos << endl;  // 2

    // Изменение
    name[0] = 'B';  // Blice
    cout << "Modified: " << name << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int x = 10;
    int* ptr = &x;  // указатель на переменную x

    // & - оператор адреса
    cout << "Адрес x: " << &x << endl;
    cout << "Значение ptr: " << ptr << endl;

    // * - оператор разыменования (получение значения)
    cout << "Значение переменной: " << *ptr << endl;  // 10

    // Изменение значения через указатель
    *ptr = 20;
    cout << "x теперь: " << x << endl;  // 20
    cout << "*ptr теперь: " << *ptr << endl;  // 20

    // Размер указателя
    cout << "Размер указателя: " << sizeof(ptr) << endl;  // 8 (64-bit)

    return 0;
}

#include <iostream>
using namespace std;

// Функция, которая изменяет переменную через ссылку
void increment(int& x) {
    x++;
}

// Функция с const ссылкой (не изменяет)
void print(const string& text) {
    cout << "Text: " << text << endl;
}

int main() {
    int value = 5;
    cout << "Before: " << value << endl;  // 5

    increment(value);
    cout << "After: " << value << endl;   // 6

    string msg = "Hello";
    print(msg);  // Эффективнее, чем передавать по значению

    return 0;
}

#include <iostream>
using namespace std;

class Car {
private:
    string color;
    double speed;

public:
    // Конструктор
    Car(string c, double s) : color(c), speed(s) {}

    // Методы
    void drive() {
        cout << "Driving a " << color << " car at " << speed << " km/h" << endl;
    }

    void accelerate() {
        speed += 10;
    }

    // Getter
    double getSpeed() const {
        return speed;
    }
};

int main() {
    Car car1("Red", 100);
    car1.drive();

    car1.accelerate();
    cout << "New speed: " << car1.getSpeed() << " km/h" << endl;

    Car car2("Blue", 120);
    car2.drive();

    return 0;
}

#include <iostream>
using namespace std;

class Animal {
protected:
    string name;

public:
    Animal(string n) : name(n) {}

    virtual void sound() {
        cout << name << " makes a sound" << endl;
    }
};

class Dog : public Animal {
public:
    Dog(string n) : Animal(n) {}

    void sound() override {
        cout << name << " barks: Woof! Woof!" << endl;
    }
};

class Cat : public Animal {
public:
    Cat(string n) : Animal(n) {}

    void sound() override {
        cout << name << " meows: Meow! Meow!" << endl;
    }
};

int main() {
    Dog dog("Rex");
    Cat cat("Whiskers");

    dog.sound();   // Rex barks: Woof! Woof!
    cat.sound();   // Whiskers meows: Meow! Meow!

    return 0;
}

#include <iostream>
#include <vector>
using namespace std;

class Shape {
public:
    virtual void draw() = 0;  // чистая виртуальная функция
    virtual ~Shape() {}  // виртуальный деструктор
};

class Circle : public Shape {
public:
    void draw() override {
        cout << "Drawing a circle" << endl;
    }
};

class Rectangle : public Shape {
public:
    void draw() override {
        cout << "Drawing a rectangle" << endl;
    }
};

int main() {
    vector<Shape*> shapes;
    shapes.push_back(new Circle());
    shapes.push_back(new Rectangle());
    shapes.push_back(new Circle());

    // Полиморфизм: каждый объект вызовет свой draw()
    for (Shape* shape : shapes) {
        shape->draw();
    }

    // Очистка памяти
    for (Shape* shape : shapes) {
        delete shape;
    }

    return 0;
}

#include <iostream>
using namespace std;

// Функция-шаблон для нахождения максимума
template <typename T>
T max(T a, T b) {
    return (a > b) ? a : b;
}

// Функция-шаблон для вывода массива
template <typename T>
void printArray(T arr[], int size) {
    for (int i = 0; i < size; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;
}

int main() {
    // Работает с int
    cout << "Max of 5 and 10: " << max(5, 10) << endl;

    // Работает с double
    cout << "Max of 3.14 and 2.71: " << max(3.14, 2.71) << endl;

    // Работает с string
    cout << "Max of \"apple\" and \"banana\": " << max(string("apple"), string("banana")) << endl;

    // Массивы
    int intArr[] = {1, 2, 3, 4, 5};
    double doubleArr[] = {1.1, 2.2, 3.3};

    printArray(intArr, 5);
    printArray(doubleArr, 3);

    return 0;
}

