    // Доступ к элементам
    cout << "First: " << v[0] << endl;
    cout << "Last: " << v.back() << endl;  // 30

    // Итерирование
    for (int num : v) {
        cout << num << " ";
    }
    cout << endl;

    // Удаление
    v.pop_back();  // удалить последний
    cout << "After pop_back: " << v.size() << endl;  // 2

    return 0;
}
